const crypto = require('crypto');

const apiSecret = 'TRx41hms7_kweGh61FMy5SZhgLs';
const timestamp = Math.floor(Date.now() / 1000);
const folder = 'cotizaciones';
const paramsToSign = `folder=${folder}&timestamp=${timestamp}${apiSecret}`;
const signature = crypto.createHash('sha1').update(paramsToSign).digest('hex');

const binaryKeys = Object.keys($input.first().binary);
const logoKey = binaryKeys.find(k => k.toLowerCase().includes('logo')) || binaryKeys[0];

const binary = {};
binary['file'] = $input.first().binary[logoKey];

return [{
  json: {
    ...($input.first().json),
    api_key: '238313899787824',
    timestamp: timestamp.toString(),
    signature: signature,
    folder: folder
  },
  binary: binary
}];

const cloudinaryResponse = $input.first().json;
const prevData = $('On form submission').first().json;

return [{
  json: {
    ...prevData,
    logo_url: cloudinaryResponse.secure_url || cloudinaryResponse.url
  }
}];

